34	// --- Random Number Generation ---
35	struct RandomGenerator {
36	    std::mt19937 rng;
37	    RandomGenerator() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
38	
39	    int an_int(int min_val, int max_val) {
40	        if (min_val > max_val) return min_val;
41	        std::uniform_int_distribution<int> dist(min_val, max_val);
42	        return dist(rng);
43	    }
44	
45	    double a_double(double min_val, double max_val) {
46	        std::uniform_real_distribution<double> dist(min_val, max_val);
47	        return dist(rng);
48	    }
49	} RGen;
