161	struct BeamNode {
162	    State current_board_state;
163	    std::vector<int> partial_plan_D; 
164	
165	    BeamNode() = default;
166	    BeamNode(State state, std::vector<int> plan)
167	        : current_board_state(std::move(state)), partial_plan_D(std::move(plan)) {}
168	    
169	    bool operator<(const BeamNode& other) const { 
170	        return current_board_state.energy_cost < other.current_board_state.energy_cost;
171	    }
172	};
