174	std::vector<int> generate_initial_plan_beam_search(
175	    const std::vector<std::vector<int>>& initial_stacks_param,
176	    int N_CONST, int M_CONST, int beam_width_param, double max_duration_for_beam_search) {
177	    
178	    std::vector<BeamNode> beam;
179	    beam.reserve(beam_width_param); 
180	    
181	    State initial_state_for_beam(N_CONST, M_CONST, initial_stacks_param, false); 
182	    beam.emplace_back(std::move(initial_state_for_beam), std::vector<int>());
183	    if (N_CONST > 0) beam.back().partial_plan_D.reserve(N_CONST);
184	    
185	    std::vector<BeamNode> candidates;
186	    if (M_CONST > 0) candidates.reserve(beam_width_param * M_CONST + 5);
187	    else candidates.reserve(beam_width_param + 5);
188	
189	
190	    for (int k_target_box = 0; k_target_box < N_CONST; ++k_target_box) {
191	        double elapsed_seconds_so_far = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
192	        bool time_is_up = elapsed_seconds_so_far > max_duration_for_beam_search;
193	        
194	        if (time_is_up) {
195	            if (beam.empty()) { 
196	                 std::vector<int> emergency_plan(N_CONST); 
197	                 if (N_CONST == 0) return emergency_plan;
198	                 for (int i = 0; i < N_CONST; ++i) emergency_plan[i] = RGen.an_int(0, M_CONST - 1);
199	                 return emergency_plan;
200	            }
201	            std::sort(beam.begin(), beam.end()); 
202	            BeamNode& best_node_so_far = beam[0]; 
203	                
204	            for (int k_future = k_target_box; k_future < N_CONST; ++k_future) {
205	                State& S_greedy = best_node_so_far.current_board_state;
206	                int f_target_val = k_future; 
207	                int f_src_idx = S_greedy.box_pos[f_target_val].first;
208	                int f_h_idx = S_greedy.box_pos[f_target_val].second;
209	                int f_num_top = S_greedy.stacks[f_src_idx].size() - 1 - f_h_idx;
210	
211	                if (f_num_top == 0) { 
212	                    best_node_so_far.partial_plan_D.push_back(f_src_idx); 
213	                } else { 
214	                    int f_block_first_val = S_greedy.stacks[f_src_idx][f_h_idx + 1];
215	                    
216	                    std::span<const int> block_span_greedy;
217	                    if (f_num_top > 0) {
218	                        block_span_greedy = std::span<const int>(S_greedy.stacks[f_src_idx].data() + f_h_idx + 1, f_num_top);
219	                    }
220	                    
221	                    double min_h_eval_score = std::numeric_limits<double>::max();
222	                    int best_d_greedy = (M_CONST > 1) ? (f_src_idx + 1) % M_CONST : 0; 
223	                    
224	                    for (int d_cand = 0; d_cand < M_CONST; ++d_cand) {
225	                        if (d_cand == f_src_idx) continue; 
226	                        double h_eval_score = S_greedy.evaluate_destination_stack_choice(k_future, block_span_greedy, d_cand);
227	                        if (h_eval_score < min_h_eval_score) { 
228	                            min_h_eval_score = h_eval_score; 
229	                            best_d_greedy = d_cand; 
230	                        }
231	                    }
232	                    best_node_so_far.partial_plan_D.push_back(best_d_greedy);
233	                    S_greedy.apply_op1_move(f_block_first_val, f_num_top, best_d_greedy);
234	                }
235	                S_greedy.apply_op2_carry_out(f_target_val);
236	            }
237	            return best_node_so_far.partial_plan_D;
238	        }
239	
240	        candidates.clear();
241	        for (auto& current_beam_node : beam) {
242	            State& S_curr = current_beam_node.current_board_state; 
243	            int target_val = k_target_box; 
244	            int src_idx = S_curr.box_pos[target_val].first;
245	            int h_idx = S_curr.box_pos[target_val].second;
246	            int num_top = S_curr.stacks[src_idx].size() - 1 - h_idx;
247	
248	            if (num_top == 0) { 
249	                State next_S = S_curr; 
250	                std::vector<int> next_plan = current_beam_node.partial_plan_D;
251	                next_plan.push_back(src_idx); 
252	                next_S.apply_op2_carry_out(target_val);
253	                candidates.emplace_back(std::move(next_S), std::move(next_plan));
254	            } else { 
255	                int block_first_val = S_curr.stacks[src_idx][h_idx + 1];
256	                
257	                std::span<const int> block_span_bs;
258	                if (num_top > 0) {
259	                   block_span_bs = std::span<const int>(S_curr.stacks[src_idx].data() + h_idx + 1, num_top);
260	                }
261	
262	                for (int dest_cand = 0; dest_cand < M_CONST; ++dest_cand) {
263	                    if (dest_cand == src_idx) continue;
264	                    State next_S = S_curr; 
265	                    std::vector<int> next_plan = current_beam_node.partial_plan_D;
266	                    next_plan.push_back(dest_cand);
267	                    next_S.apply_op1_move(block_first_val, num_top, dest_cand);
268	                    next_S.apply_op2_carry_out(target_val);
269	                    candidates.emplace_back(std::move(next_S), std::move(next_plan));
270	                }
271	            }
272	        }
273	        
274	        if (candidates.empty()) { 
275	            std::vector<int> emergency_plan(N_CONST);
276	            if (N_CONST == 0) return emergency_plan;
277	            if (beam.empty() && N_CONST > 0) { 
278	                 for (int i = 0; i < N_CONST; ++i) emergency_plan[i] = RGen.an_int(0, M_CONST - 1);
279	                 return emergency_plan;
280	            }
281	            // If candidates is empty but beam was not (e.g. M=1 case for Op1 where no valid dest_cand)
282	            // For M=10, this shouldn't happen unless beam_width is too small or other issues.
283	            // Fallback to random plan completion from best current beam node.
284	            // This is tricky, for now, if candidates is empty, signal failure for this path.
285	            // The outer logic will pick best from beam if one exists or ultimately generate full random.
286	            // If `beam` was non-empty but all paths led to no candidates, return best plan so far or random.
287	            // The current fallback is just random full plan.
288	            for (int i = 0; i < N_CONST; ++i) emergency_plan[i] = RGen.an_int(0, M_CONST - 1);
289	            return emergency_plan;
290	        }
291	
292	        std::sort(candidates.begin(), candidates.end());
293	
294	        beam.clear();
295	        for (size_t i = 0; i < std::min((size_t)beam_width_param, candidates.size()); ++i) {
296	            beam.push_back(std::move(candidates[i]));
297	        }
298	        
299	        if (beam.empty() && N_CONST > 0) { 
300	            std::vector<int> emergency_plan(N_CONST);
301	            for (int i = 0; i < N_CONST; ++i) emergency_plan[i] = RGen.an_int(0, M_CONST - 1);
302	            return emergency_plan;
303	        }
304	    }
305	
306	    if (beam.empty()){ 
307	        std::vector<int> emergency_plan(N_CONST);
308	        if (N_CONST == 0) return emergency_plan;
309	        for (int i = 0; i < N_CONST; ++i) emergency_plan[i] = RGen.an_int(0, M_CONST - 1);
310	        return emergency_plan;
311	    }
312	    std::sort(beam.begin(), beam.end()); 
313	    return beam[0].partial_plan_D;
314	}
