    }

    int stack_top(int s) {
        if (stacks[s].empty()) return -1;
        return stacks[s].back();
    }
};

struct Solver {
    int N, M;
    std::vector<std::vector<int>> initial_stacks;
    std::mt19937 rng;

    // Parameters
    int SPLIT_WINDOW;
    int MAX_SPLITS_PER_TARGET;
    double COVER_PENALTY_WEIGHT;
    double HEIGHT_PENALTY_WEIGHT;
    double EMPTY_BONUS;
    double SOON_TOP_BONUS;

    Solver(int n, int m, const std::vector<std::vector<int>>& init)
        : N(n), M(m), initial_stacks(init),
          rng(std::chrono::steady_clock::now().time_since_epoch().count()) {
        SPLIT_WINDOW = 40;
        MAX_SPLITS_PER_TARGET = 3;
        COVER_PENALTY_WEIGHT = 5.0;
        HEIGHT_PENALTY_WEIGHT = 0.3;
        EMPTY_BONUS = 2.0;
        SOON_TOP_BONUS = 3.0;
    }

    double score_destination(const State& state, int dest, int current_target,
                             const std::vector<int>& block_to_place, bool exposing) {
        // Lower score = better destination
        double score = 0.0;
        const auto& dst = state.stacks[dest];

        // Penalty for height (prefer shorter stacks)
        score += dst.size() * HEIGHT_PENALTY_WEIGHT;

        // Bonus for empty stacks (but not too much - preserve them)
        if (dst.empty()) {
            score -= EMPTY_BONUS;
        }

        // Heavy penalty for covering soon-needed boxes
        for (int b : dst) {
            if (b > current_target && b < current_target + SPLIT_WINDOW) {
                // This box is needed soon and we'd cover it
                double urgency = (double)(SPLIT_WINDOW - (b - current_target)) / SPLIT_WINDOW;
                score += COVER_PENALTY_WEIGHT * urgency * block_to_place.size();
            }
        }

        // Penalty for covering boxes in the block we're placing that are soon-needed
        // (these will be buried under later additions to this stack)
        // Actually, this is about how accessible the block's contents will be
        for (int i = 0; i < (int)block_to_place.size(); i++) {
            int b = block_to_place[i];
            if (b > current_target && b < current_target + SPLIT_WINDOW) {
                // This box is at position i from bottom of placed block
                // It will be at height dst.size() + i after placement
                // Boxes above it in the block: block_to_place.size() - 1 - i
                int buried_by = (int)block_to_place.size() - 1 - i;
                double urgency = (double)(SPLIT_WINDOW - (b - current_target)) / SPLIT_WINDOW;
                score += COVER_PENALTY_WEIGHT * urgency * buried_by * 0.5;
            }
        }

        // If we're exposing a soon-needed box (it's on top of block_to_place),
        // give bonus for destinations where it's less likely to be buried
        if (exposing && !block_to_place.empty()) {
            int exposed_box = block_to_place.back();
            if (exposed_box > current_target && exposed_box < current_target + SPLIT_WINDOW) {
                // Bonus for short stacks (less likely to have things added on top)
                score -= SOON_TOP_BONUS * (1.0 - (double)dst.size() / N);
            }
        }

        return score;
    }

    int choose_destination(const State& state, int src_stack, int current_target,
                           const std::vector<int>& block_to_place, bool exposing) {
        double best_score = 1e18;
        int best_dest = -1;

        for (int d = 0; d < M; d++) {
            if (d == src_stack) continue;
            double s = score_destination(state, d, current_target, block_to_place, exposing);
            if (s < best_score) {
                best_score = s;
                best_dest = d;
            }
        }
        return best_dest;
    }

    long long run_with_params(bool record_ops, std::vector<std::pair<int,int>>& out_ops) {
        State state(N, M, initial_stacks);
        if (!record_ops) state.ops.reserve(0);

        for (int k = 0; k < N; k++) {
            // Carry out any boxes that are on top in sequence
            while (k < N && state.is_on_top(k)) {
                state.carry_out(k);
                k++;
            }
            if (k >= N) break;

            int src = state.box_stack[k];
            int h = state.box_height[k];
            int block_size = (int)state.stacks[src].size() - 1 - h;

            if (block_size == 0) {
                // k is on top, carry out
                state.carry_out(k);
                continue;
            }

            // Get the block above k
            std::vector<int> block(state.stacks[src].begin() + h + 1, state.stacks[src].end());
            // block[0] is just above k, block.back() is at top of stack

            // Find soon-needed boxes in the block and their positions
            // Position in block: 0 = just above k, block_size-1 = top
            int min_label = INT_MAX;
            int min_pos = -1; // position in block (0-indexed from bottom of block)
            for (int i = 0; i < block_size; i++) {
                if (block[i] < min_label) {
                    min_label = block[i];
                    min_pos = i;
                }
            }

            bool should_split = (min_label <= k + SPLIT_WINDOW) && (min_pos < block_size - 1);

            if (should_split) {
                // Strategy: peel from top down to expose soon-needed boxes
                // We'll do up to MAX_SPLITS_PER_TARGET splits

                // Find important boxes (soon-needed) sorted by position from top
                struct ImportantBox { int label; int pos; };
                std::vector<ImportantBox> important;
                for (int i = 0; i < block_size; i++) {
                    if (block[i] >= k + 1 && block[i] <= k + SPLIT_WINDOW) {
                        important.push_back({block[i], i});
                    }
                }
                // Sort by label (extraction order) - we want to expose the soonest-needed
                std::sort(important.begin(), important.end(),
                    [](const ImportantBox& a, const ImportantBox& b) { return a.label < b.label; });

                // Find the most valuable box to expose:
                // The one that's soonest needed AND not already on top
                int expose_target = -1;
                int expose_pos = -1;
                for (auto& ib : important) {
                    if (ib.pos < block_size - 1) { // not already on top
                        expose_target = ib.label;
                        expose_pos = ib.pos;
                        break;
                    }
                }

                if (expose_target >= 0) {
                    // Split: move [expose_pos+1 ... block_size-1] to dest1
                    //         move [0 ... expose_pos] to dest2 (expose_target on top)
                    int top_portion_size = block_size - 1 - expose_pos;
                    int bottom_portion_size = expose_pos + 1;

                    // Can we do a second-level split on the top portion?
                    // For now, just do single split
                    if (top_portion_size > 0) {
                        std::vector<int> top_block(block.begin() + expose_pos + 1, block.end());
                        int first_box_top = block[expose_pos + 1];
                        int dest1 = choose_destination(state, src, k, top_block, false);
                        state.move_block(first_box_top, dest1);
                    }

                    // Now move the bottom portion (expose_target on top)
                    std::vector<int> bot_block(block.begin(), block.begin() + expose_pos + 1);
                    int first_box_bot = block[0];
                    int dest2 = choose_destination(state, src, k, bot_block, true);
                    state.move_block(first_box_bot, dest2);

                    // Carry out k
                    state.carry_out(k);
                } else {
                    // Min is already on top or no good candidate - move whole block
                    std::vector<int> whole_block(block.begin(), block.end());
                    int first_box = block[0];
                    int dest = choose_destination(state, src, k, whole_block,
                                                 min_pos == block_size - 1);
                    state.move_block(first_box, dest);
                    state.carry_out(k);
                }
            } else {
                // No split - move whole block to best destination
                std::vector<int> whole_block(block.begin(), block.end());
                int first_box = block[0];
                int dest = choose_destination(state, src, k, whole_block,
                                             min_pos == block_size - 1);
                state.move_block(first_box, dest);
                state.carry_out(k);
            }
        }

        if (record_ops) out_ops = std::move(state.ops);
        return state.energy;
    }

    // Try parameter variations to find better settings
    void optimize_params(double time_limit) {
        std::vector<std::pair<int,int>> dummy_ops;
        long long best_energy = run_with_params(false, dummy_ops);

        int best_window = SPLIT_WINDOW;
        double best_cover = COVER_PENALTY_WEIGHT;
        double best_height = HEIGHT_PENALTY_WEIGHT;
        double best_empty = EMPTY_BONUS;
        double best_soon = SOON_TOP_BONUS;

        std::uniform_real_distribution<double> dist(0.0, 1.0);

        while (elapsed() < time_limit) {
            // Perturb parameters
            int old_window = SPLIT_WINDOW;
            double old_cover = COVER_PENALTY_WEIGHT;
            double old_height = HEIGHT_PENALTY_WEIGHT;
            double old_empty = EMPTY_BONUS;
            double old_soon = SOON_TOP_BONUS;

            double choice = dist(rng);
            if (choice < 0.2) {
                SPLIT_WINDOW = std::max(5, std::min(100, SPLIT_WINDOW + (int)(dist(rng) * 20) - 10));
            } else if (choice < 0.4) {
                COVER_PENALTY_WEIGHT = std::max(0.1, COVER_PENALTY_WEIGHT + (dist(rng) - 0.5) * 3.0);
            } else if (choice < 0.6) {
                HEIGHT_PENALTY_WEIGHT = std::max(0.0, HEIGHT_PENALTY_WEIGHT + (dist(rng) - 0.5) * 0.3);
            } else if (choice < 0.8) {
                EMPTY_BONUS = std::max(0.0, EMPTY_BONUS + (dist(rng) - 0.5) * 2.0);
            } else {
                SOON_TOP_BONUS = std::max(0.0, SOON_TOP_BONUS + (dist(rng) - 0.5) * 2.0);
            }

            long long new_energy = run_with_params(false, dummy_ops);

            if (new_energy < best_energy) {
                best_energy = new_energy;
                best_window = SPLIT_WINDOW;
                best_cover = COVER_PENALTY_WEIGHT;
                best_height = HEIGHT_PENALTY_WEIGHT;
                best_empty = EMPTY_BONUS;
                best_soon = SOON_TOP_BONUS;
            } else {
                // Revert
                SPLIT_WINDOW = old_window;
                COVER_PENALTY_WEIGHT = old_cover;
                HEIGHT_PENALTY_WEIGHT = old_height;
                EMPTY_BONUS = old_empty;
                SOON_TOP_BONUS = old_soon;
            }
        }

        // Restore best params
        SPLIT_WINDOW = best_window;
        COVER_PENALTY_WEIGHT = best_cover;
        HEIGHT_PENALTY_WEIGHT = best_height;
        EMPTY_BONUS = best_empty;
        SOON_TOP_BONUS = best_soon;
    }
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;

    std::vector<std::vector<int>> stacks(M);
    for (int i = 0; i < M; i++) {
        stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> stacks[i][j];
            stacks[i][j]--; // 0-indexed
        }
    }

    Solver solver(N, M, stacks);

    // Optimize parameters using remaining time
    solver.optimize_params(1.85);

    // Final run with best params, recording ops
    std::vector<std::pair<int,int>> final_ops;
    solver.run_with_params(true, final_ops);

    for (auto& [v, i] : final_ops) {
        std::cout << v << " " << i << "\n";
    }

    return 0;
}
