# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>
#include <chrono>
#include <random>
#include <cmath>
#include <cassert>

auto GLOBAL_START = std::chrono::steady_clock::now();

double elapsed() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START).count();
}

struct State {
    std::vector<std::vector<int>> stacks;
    std::vector<int> box_stack;
    std::vector<int> box_height;
    int N, M;
    long long energy;
    std::vector<std::pair<int,int>> ops;
    bool record;

    State() : N(0), M(0), energy(0), record(false) {}

    State(int n, int m, const std::vector<std::vector<int>>& init, bool rec = false)
        : N(n), M(m), energy(0), record(rec) {
        stacks = init;
        box_stack.resize(N);
        box_height.resize(N);
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_stack[stacks[i][j]] = i;
                box_height[stacks[i][j]] = j;
            }
        }
    }

    void move_block(int box_v, int dest) {
        int src = box_stack[box_v];
        int h = box_height[box_v];
        int num = (int)stacks[src].size() - h;
        int dh = (int)stacks[dest].size();

        for (int i = h; i < h + num; i++) {
            int b = stacks[src][i];
            box_stack[b] = dest;
            box_height[b] = dh + (i - h);
            stacks[dest].push_back(b);
        }
        stacks[src].resize(h);
        energy += (num + 1);
        if (record) ops.push_back({box_v + 1, dest + 1});
    }

    void carry_out(int box_v) {
        int src = box_stack[box_v];
        stacks[src].pop_back();
        if (record) ops.push_back({box_v + 1, 0});
    }

    bool is_on_top(int box_v) const {
        int src = box_stack[box_v];
        return box_height[box_v] == (int)stacks[src].size() - 1;
    }

    int blocks_above(int box_v) const {
        int src = box_stack[box_v];
        return (int)stacks[src].size() - 1 - box_height[box_v];
    }
};

// A "move" for extracting target k: describes how to split the block above k
struct Move {
    // splits[i] = {first_box_in_piece, dest_stack}
    // Applied from top to bottom (first split peels off the top portion)
    std::vector<std::pair<int, int>> splits;
};

// Fast greedy: move entire block above target to best heuristic destination
int fast_greedy_dest(const State& state, int target_k) {
    int src = state.box_stack[target_k];
    int h = state.box_height[target_k];
    int block_size = (int)state.stacks[src].size() - 1 - h;

    if (block_size == 0) return -1; // no move needed

    double best_score = 1e18;
    int best_dest = -1;

    for (int d = 0; d < state.M; d++) {
        if (d == src) continue;
        double score = 0;
        const auto& dst = state.stacks[d];

        // Penalty for covering soon-needed boxes in destination
        for (int b : dst) {
            if (b > target_k && b < target_k + 30) {
                double urgency = (30.0 - (b - target_k)) / 30.0;
                score += 5.0 * urgency * block_size;
            }
        }

        // Penalty for height
        score += dst.size() * 0.2;

        // Bonus for empty (but conserve empties)
        if (dst.empty()) score -= 1.5;

        // Bonus for putting soon-needed box on top
        int top_of_block = state.stacks[src].back();
        if (top_of_block > target_k && top_of_block < target_k + 15) {
            // This box will be on top of dest after move
            score -= 3.0 * (15.0 - (top_of_block - target_k)) / 15.0;
        }

        if (score < best_score) {
            best_score = score;
            best_dest = d;
        }
    }
    return best_dest;
}

// Simulate extraction of target_k with a simple greedy (whole block move)
// Returns additional energy cost
long long simulate_one_extraction_greedy(State& state, int target_k) {
    long long before = state.energy;

    if (state.is_on_top(target_k)) {
        state.carry_out(target_k);
        return 0;
    }

    int dest = fast_greedy_dest(state, target_k);
    int src = state.box_stack[target_k];
    int h = state.box_height[target_k];
    int first_box = state.stacks[src][h + 1];
    state.move_block(first_box, dest);
    state.carry_out(target_k);

    return state.energy - before;
}

// Rollout: simulate next W extractions using fast greedy, return total energy
long long rollout(State state, int start_k, int window) {
    long long before = state.energy;
    int end_k = std::min(state.N, start_k + window);
    for (int k = start_k; k < end_k; k++) {
        simulate_one_extraction_greedy(state, k);
    }
    return state.energy - before;
}

// Generate candidate moves for extracting target_k
// Returns vector of (description, state-after-applying-move)
struct Candidate {
    long long immediate_cost;
    std::vector<std::pair<int,int>> move_ops; // (box_v 0-indexed, dest 0-indexed)
};

std::vector<Candidate> generate_candidates(const State& state, int target_k, int max_candidates) {
    std::vector<Candidate> candidates;
    int src = state.box_stack[target_k];
    int h = state.box_height[target_k];
    int block_size = (int)state.stacks[src].size() - 1 - h;

    if (block_size == 0) {
        // No moves needed, just carry out
        candidates.push_back({0, {}});
        return candidates;
    }

    int M = state.M;

    // Type 1: Move entire block to each possible destination (9 candidates)
    for (int d = 0; d < M; d++) {
        if (d == src) continue;
        int first_box = state.stacks[src][h + 1];
        long long cost = block_size + 1;
        candidates.push_back({cost, {{first_box, d}}});
    }

    // Type 2: Split into top-1 + rest (peel top box off separately)
    if (block_size >= 2) {
        int top_box = state.stacks[src].back();
        int second_box = state.stacks[src][h + 1]; // first box of remaining block

        for (int d1 = 0; d1 < M; d1++) {
            if (d1 == src) continue;
            // Move top box to d1, then move rest to best greedy dest
            // But also try a few destinations for the rest
            for (int d2 = 0; d2 < M; d2++) {
                if (d2 == src) continue;
                long long cost = 2 + (block_size - 1 + 1); // top costs 2, rest costs (block_size-1)+1
                candidates.push_back({cost, {{top_box, d1}, {second_box, d2}}});
                if ((int)candidates.size() >= max_candidates) goto done;
            }
        }
    }

    // Type 3: Split into top-2 + rest
    if (block_size >= 3 && (int)candidates.size() < max_candidates) {
        int split_box = state.stacks[src][h + block_size - 1]; // second from top
        int rest_box = state.stacks[src][h + 1]; // first box of remaining

        for (int d1 = 0; d1 < M; d1++) {
            if (d1 == src) continue;
            int best_d2 = fast_greedy_dest(state, target_k); // heuristic for rest
            if (best_d2 == -1) best_d2 = (src + 1) % M;
            long long cost = 3 + (block_size - 2 + 1);
            candidates.push_back({cost, {{split_box, d1}, {rest_box, best_d2}}});
            if ((int)candidates.size() >= max_candidates) goto done;
        }
    }

    // Type 4: Multi-split - peel off top K boxes individually
    if (block_size >= 3 && (int)candidates.size() < max_candidates) {
        // Find soon-needed boxes in the block
        for (int peel = 1; peel <= std::min(3, block_size - 1); peel++) {
            int box_to_peel = state.stacks[src][h + block_size - peel]; // peel from top
            if (box_to_peel > target_k && box_to_peel < target_k + 20) {
                // This box is soon-needed, worth individual placement
                // Try putting it on lowest stack
                int min_h_dest = -1;
                int min_h = INT_MAX;
                for (int d = 0; d < M; d++) {
                    if (d == src) continue;
                    if ((int)state.stacks[d].size() < min_h) {
                        min_h = state.stacks[d].size();
                        min_h_dest = d;
                    }
                }
                if (min_h_dest >= 0) {
                    // Build a multi-peel move
                    std::vector<std::pair<int,int>> move_ops;
                    long long cost = 0;
                    // Peel top 'peel' boxes one at a time
                    for (int p = 0; p < peel; p++) {
                        int bp = state.stacks[src][h + block_size - 1 - p];
                        move_ops.push_back({bp, min_h_dest});
                        cost += 2; // each single box costs 2
                    }
                    // Move remaining block
                    int rest_size = block_size - peel;
                    if (rest_size > 0) {
                        int rest_first = state.stacks[src][h + 1];
                        int rest_dest = (min_h_dest == src) ? (src + 1) % M : min_h_dest;
                        // Actually use fast_greedy_dest but we don't have a good state...
                        // Just use a different dest
                        rest_dest = -1;
                        int best_rscore = INT_MAX;
                        for (int d = 0; d < M; d++) {
                            if (d == src) continue;
                            int sc = state.stacks[d].size();
                            // Penalize covering soon-needed
                            for (int b : state.stacks[d]) {
                                if (b > target_k && b < target_k + 20) sc += 10;
                            }
                            if (sc < best_rscore) {
                                best_rscore = sc;
                                rest_dest = d;
                            }
                        }
                        move_ops.push_back({rest_first, rest_dest});
                        cost += rest_size + 1;
                    }
                    candidates.push_back({cost, move_ops});
                    if ((int)candidates.size() >= max_candidates) goto done;
                }
            }
        }
    }

done:
    return candidates;
}

State apply_candidate(const State& state, int target_k, const Candidate& cand) {
    State s = state;
    for (auto& [box_v, dest] : cand.move_ops) {
        s.move_block(box_v, dest);
    }
    s.carry_out(target_k);
    return s;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;

    std::vector<std::vector<int>> init_stacks(M);
    for (int i = 0; i < M; i++) {
        init_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> init_stacks[i][j];
            init_stacks[i][j]--;
        }
    }

    // Phase 1: Rollout-based greedy (use remaining time budget)
    double time_budget = 1.90;
