    // Compact representation: stacks stored as arrays
    int stack_data[10][210]; // stacks[i][j] = box at height j in stack i
    int stack_size[10];
    int box_stack[MAXN]; // which stack
    int box_height[MAXN]; // height in stack
    int N, M;
    long long energy;

    void init(int n, int m, const std::vector<std::vector<int>>& stacks_in) {
        N = n; M = m; energy = 0;
        for (int i = 0; i < m; i++) {
            stack_size[i] = stacks_in[i].size();
            for (int j = 0; j < stack_size[i]; j++) {
                stack_data[i][j] = stacks_in[i][j];
                box_stack[stacks_in[i][j]] = i;
                box_height[stacks_in[i][j]] = j;
            }
        }
    }

    void copy_from(const State& o) {
        N = o.N; M = o.M; energy = o.energy;
        for (int i = 0; i < M; i++) {
            stack_size[i] = o.stack_size[i];
            for (int j = 0; j < stack_size[i]; j++)
                stack_data[i][j] = o.stack_data[i][j];
        }
        for (int i = 0; i < N; i++) {
            box_stack[i] = o.box_stack[i];
            box_height[i] = o.box_height[i];
        }
    }

    inline void move_block_to(int box_v, int dest) {
        int src = box_stack[box_v];
        int h = box_height[box_v];
        int num = stack_size[src] - h;
        int dh = stack_size[dest];

        for (int i = 0; i < num; i++) {
            int b = stack_data[src][h + i];
            stack_data[dest][dh + i] = b;
            box_stack[b] = dest;
            box_height[b] = dh + i;
        }
        stack_size[dest] += num;
        stack_size[src] = h;
        energy += (num + 1);
    }

    inline void carry_out(int box_v) {
        int src = box_stack[box_v];
        stack_size[src]--;
    }

    inline bool is_on_top(int box_v) const {
        return box_height[box_v] == stack_size[box_stack[box_v]] - 1;
    }

    inline int above_count(int box_v) const {
        return stack_size[box_stack[box_v]] - 1 - box_height[box_v];
    }
};

// Fast greedy destination choice
inline int greedy_dest(const State& st, int target_k) {
    int src = st.box_stack[target_k];
    int h = st.box_height[target_k];
    int block_size = st.stack_size[src] - 1 - h;

    int best_dest = -1;
    double best_score = 1e18;

    for (int d = 0; d < st.M; d++) {
        if (d == src) continue;
        double score = 0;

        // Penalty for covering soon-needed boxes
        int ds = st.stack_size[d];
        for (int j = 0; j < ds; j++) {
            int b = st.stack_data[d][j];
            if (b > target_k && b < target_k + 30) {
                score += 5.0 * (30.0 - (b - target_k)) / 30.0 * block_size;
            }
        }

        // Height penalty
        score += ds * 0.2;

        // Empty bonus
        if (ds == 0) score -= 2.0;

        // Soon-needed-on-top bonus: if top of moved block is soon-needed
        int top_box = st.stack_data[src][st.stack_size[src] - 1];
        if (top_box > target_k && top_box < target_k + 20) {
            score -= 3.0 * (20.0 - (top_box - target_k)) / 20.0;
        }

        if (score < best_score) {
            best_score = score;
            best_dest = d;
        }
    }
    return best_dest;
}

