long long simulate_greedy(State& st, int start_k) {
    for (int k = start_k; k < st.N; k++) {
        if (st.is_on_top(k)) {
            st.carry_out(k);
            continue;
        }
        int dest = greedy_dest(st, k);
        int src = st.box_stack[k];
        int first_box = st.stack_data[src][st.box_height[k] + 1];
        st.move_block_to(first_box, dest);
        st.carry_out(k);
    }
    return st.energy;
}

// Pool of states to avoid allocation
