    int since_rebuild = 0;

    while (true) {
        double t = elapsed();
        if (t >= sa_end) break;

        double progress = (t - sa_start) / sa_budget;
        if (progress > 1.0) break;
        double T = T_init * std::pow(T_final / T_init, progress);

        memcpy(new_plan, plan, sizeof(plan));

        // Choose mutation
        int mutation_type = rng() % 100;
        int change_start = N; // earliest changed index

        if (mutation_type < 50) {
            // Single point
            int idx = rng() % N;
            new_plan[idx] = rng() % M;
            change_start = idx;
        } else if (mutation_type < 85) {
            // Block change (2-15 positions)
            int idx = rng() % N;
            int len = 2 + rng() % 14;
            change_start = idx;
            for (int i = 0; i < len; i++) {
                int p = (idx + i) % N;
                new_plan[p] = rng() % M;
                if (p < change_start) change_start = p;
            }
        } else if (mutation_type < 95) {
            // Swap two positions' destinations
            int a = rng() % N;
            int b = rng() % N;
            std::swap(new_plan[a], new_plan[b]);
            change_start = std::min(a, b);
        } else {
            // Block shift: shift a segment's destinations by 1
            int idx = rng() % N;
            int len = 2 + rng() % 10;
            change_start = idx;
            for (int i = 0; i < len; i++) {
                int p = (idx + i) % N;
                new_plan[p] = (new_plan[p] + 1) % M;
                if (p < change_start) change_start = p;
            }
        }

