                memcpy(best_plan, new_plan, sizeof(plan));
            }
            improvements++;
            since_rebuild++;
            if (since_rebuild >= 500) {
                rebuild_checkpoints();
                since_rebuild = 0;
            }
        } else {
            double delta = (double)(new_energy - current_energy);
            if (((double)(rng() % 10000) / 10000.0) < std::exp(-delta / T)) {
                current_energy = new_energy;
                memcpy(plan, new_plan, sizeof(plan));
                since_rebuild++;
                if (since_rebuild >= 500) {
                    rebuild_checkpoints();
                    since_rebuild = 0;
                }
            }
